const input = $input.first().json;
const body = (input.body && input.body.event) ? input.body : input;
const rawEvent = (body.event || body.type || '').toLowerCase().replace(/_/g, '.');
console.log('[FILTRO] event:', rawEvent, '| instance:', body.instance);

if (rawEvent !== 'messages.upsert') { console.log('[FILTRO] Ignorado:', rawEvent); return []; }

const data = body.data || {};
let msg;
if (Array.isArray(data.messages) && data.messages.length > 0) { msg = data.messages[0]; }
else if (data.key) { msg = data; }
else { console.log('[FILTRO] Sem mensagem em data'); return []; }

const key       = msg.key || {};
const remoteJid = key.remoteJid || '';
const fromMe    = key.fromMe === true;
if (!remoteJid) return [];
if (remoteJid.includes('@g.us')) { console.log('[FILTRO] Grupo ignorado'); return []; }

const msgObj   = msg.message || {};
const pushName = msg.pushName || 'Cliente';
const instance = body.instance || '';

let type = 'unknown', content = '', hasMedia = false;

if (msgObj.conversation !== undefined)         { type = 'conversation';   content = msgObj.conversation || ''; }
else if (msgObj.extendedTextMessage)           { type = 'conversation';   content = msgObj.extendedTextMessage.text || ''; }
else if (msgObj.audioMessage || msgObj.pttMessage) { type = 'audioMessage';  hasMedia = true; }
else if (msgObj.imageMessage)                  { type = 'imageMessage';   content = msgObj.imageMessage.caption || '[Imagem recebida]'; hasMedia = true; }
else if (msgObj.documentMessage)               { type = 'documentMessage'; content = msgObj.documentMessage.caption || '[Documento recebido]'; hasMedia = true; }
else if (msgObj.buttonsResponseMessage)        { type = 'conversation';   content = msgObj.buttonsResponseMessage.selectedDisplayText || ''; }
else if (msgObj.listResponseMessage)           { type = 'conversation';   content = msgObj.listResponseMessage.title || ''; }
else if (msgObj.reactionMessage || msgObj.protocolMessage || msgObj.stickerMessage) { return []; }
else { console.log('[FILTRO] Tipo nao suportado:', Object.keys(msgObj).join(', ')); return []; }

if (!content && !hasMedia) return [];
console.log('[FILTRO] OK — type:', type, '| remoteJid:', remoteJid);
return [{ json: { remoteJid, fromMe, pushName, type, content, hasMedia, instance, msgId: key.id } }];

const sd = $getWorkflowStaticData('global');
const d  = $input.first().json;
const { remoteJid, fromMe, pushName } = d;

if (!sd.convs) sd.convs = {};
const c = sd.convs[remoteJid] || { state: 'new', history: [], name: pushName, startedAt: new Date().toISOString() };

let action = 'process_ai';
if      (c.state === 'human_takeover')      action = 'skip';
else if (c.state === 'pre_attendance_done') action = 'skip';
else if (fromMe && (c.state === 'active_ai' || c.state === 'new')) action = 'human_takeover';
else if (fromMe) action = 'skip';

return [{ json: { ...d, action, convState: c.state, history: c.history || [], custName: c.name || pushName } }];

const sd = $getWorkflowStaticData('global');
const { remoteJid } = $input.first().json;
if (!sd.convs) sd.convs = {};
if (!sd.convs[remoteJid]) sd.convs[remoteJid] = { state: 'new', history: [] };
sd.convs[remoteJid].state   = 'human_takeover';
sd.convs[remoteJid].humanAt = new Date().toISOString();
console.log('[TAKEOVER] Humano assumiu: ' + remoteJid);
return [{ json: { ok: true, remoteJid } }];

const input = $input.first().json;
const { remoteJid, fromMe, pushName, type, content, hasMedia, instance } = input;

let userMessage = content || '';

// Áudio: content já vem transcrito — passa direto com prefixo informativo
if (type === 'audioMessage') {
  userMessage = '[mensagem de voz]: ' + content;
} else if (type === 'imageMessage') {
  userMessage = '[Cliente enviou uma imagem]: ' + content;
} else if (type === 'documentMessage') {
  userMessage = '[Cliente enviou um documento]: ' + content;
}

return [{ json: { remoteJid, pushName, instance, content: userMessage, type } }];

const sd = $getWorkflowStaticData('global');

// Resposta do AI Agent
let aiResp = $input.first().json.output || '';
if (!aiResp) aiResp = 'Olá! Tive uma dificuldade técnica. Pode repetir sua mensagem?';

// Contexto de "Preparar Request IA"
const ctx       = $('Preparar Request IA').first().json;
const remoteJid = ctx.remoteJid || '';
const pushName  = ctx.pushName  || 'Cliente';
const instance  = ctx.instance  || '';

console.log('[PARSE] remoteJid:', remoteJid, '| resp:', aiResp.slice(0, 60));

// Checar flag de conclusão
const FLAG      = '[PRE_ATENDIMENTO_CONCLUIDO]';
const concluded = aiResp.includes(FLAG);
const clean     = aiResp.replace(FLAG, '').trim();

// Atualizar estado (histórico fica no Postgres via AI Agent)
if (!sd.convs) sd.convs = {};
if (!sd.convs[remoteJid]) sd.convs[remoteJid] = { state: 'new', startedAt: new Date().toISOString() };
sd.convs[remoteJid].state = concluded ? 'pre_attendance_done' : 'active_ai';
sd.convs[remoteJid].name  = pushName;
if (concluded) sd.convs[remoteJid].concludedAt = new Date().toISOString();

console.log('[PARSE] Concluido:', concluded, '| Estado:', sd.convs[remoteJid].state);
return [{ json: { remoteJid, instance, aiResp: clean, concluded, pushName } }];

const whisperResp = $input.first().json;
const original    = $('Filtrar e Extrair').first().json;

const transcription = (whisperResp.text || '').trim();
console.log('[AUDIO] Transcrição Whisper:', transcription ? transcription.slice(0, 100) : '(vazia)');

return [{ json: {
  remoteJid: original.remoteJid,
  fromMe:    original.fromMe,
  pushName:  original.pushName,
  type:      'conversation',
  content:   transcription || '[áudio não transcrito]',
  hasMedia:  false,
  instance:  original.instance,
  msgId:     original.msgId
} }];

const inputData = $input.first().json;
const base64   = inputData.base64;
const fileName = inputData.fileName || 'audio.ogg';
const mimeType = inputData.mimetype || 'audio/ogg; codecs=opus';

if (!base64) throw new Error('base64 não encontrado na resposta do Baixar Audio');

const buffer     = Buffer.from(base64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);

return [{ json: {}, binary: { data: binaryData } }];

